  // ─── 6c. HESS'S LAW CYCLE ────────────────────────────────────────────────────
  static hessLawCycleSvg = `<?xml version="1.0" encoding="utf-8"?>
<svg version="1.1" xmlns="http://www.w3.org/2000/svg"
     width="1000px" height="600px" viewBox="0 0 1000 600">
  <defs>
    <pattern id="hess_hatch" patternUnits="userSpaceOnUse" width="6" height="6" patternTransform="rotate(45)">
      <line x1="0" y1="0" x2="0" y2="6" stroke="#000" stroke-width="1"/>
    </pattern>
    <marker id="hess_arrow" markerWidth="10" markerHeight="7" refX="10" refY="3.5" orient="auto">
      <polygon points="0 0, 10 3.5, 0 7" fill="#000"/>
    </marker>
  </defs>

  <text x="500" y="30" font-family="Georgia,serif" font-size="16" font-weight="bold" fill="#000" text-anchor="middle">Hess's Law Enthalpy Cycle</text>
  <text x="500" y="50" font-family="Georgia,serif" font-size="11" fill="#000" text-anchor="middle">ΔH₁ = ΔH₂ + ΔH₃  — the total enthalpy change is independent of the route taken</text>

  <!-- ═══ THREE COMPOUND BOXES ═══ -->
  <!-- Top left: Reactants -->
  <rect x="80" y="160" width="200" height="60" rx="6" fill="url(#hess_hatch)" fill-opacity="0.18" stroke="#000" stroke-width="2.5"/>
  <text x="180" y="185" font-family="Georgia,serif" font-size="13" font-weight="bold" fill="#000" text-anchor="middle">Reactants</text>
  <text x="180" y="203" font-family="Georgia,serif" font-size="11" fill="#000" text-anchor="middle">C(s) + O₂(g)</text>

  <!-- Top right: Products -->
  <rect x="720" y="160" width="200" height="60" rx="6" fill="url(#hess_hatch)" fill-opacity="0.18" stroke="#000" stroke-width="2.5"/>
  <text x="820" y="185" font-family="Georgia,serif" font-size="13" font-weight="bold" fill="#000" text-anchor="middle">Products</text>
  <text x="820" y="203" font-family="Georgia,serif" font-size="11" fill="#000" text-anchor="middle">CO₂(g)</text>

  <!-- Bottom centre: Intermediate -->
  <rect x="390" y="420" width="220" height="60" rx="6" fill="url(#hess_hatch)" fill-opacity="0.18" stroke="#000" stroke-width="2.5"/>
  <text x="500" y="445" font-family="Georgia,serif" font-size="13" font-weight="bold" fill="#000" text-anchor="middle">Intermediate</text>
  <text x="500" y="463" font-family="Georgia,serif" font-size="11" fill="#000" text-anchor="middle">CO(g) + ½O₂(g)</text>

  <!-- ═══ ROUTE 1: Direct arrow across top ═══ -->
  <line x1="280" y1="190" x2="720" y2="190" stroke="#000" stroke-width="3" marker-end="url(#hess_arrow)"/>
  <rect x="410" y="168" width="180" height="28" rx="4" fill="#fff" stroke="none"/>
  <text x="500" y="180" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000" text-anchor="middle">ΔH₁ (direct route)</text>
  <text x="500" y="195" font-family="Georgia,serif" font-size="10" fill="#000" text-anchor="middle">e.g. C + O₂ → CO₂</text>

  <!-- ═══ ROUTE 2: Indirect via intermediate ═══ -->
  <!-- Left leg: Reactants → Intermediate -->
  <line x1="210" y1="220" x2="430" y2="418" stroke="#000" stroke-width="2.5" stroke-dasharray="8,4" marker-end="url(#hess_arrow)"/>
  <text x="270" y="345" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">ΔH₂</text>
  <text x="240" y="360" font-family="Georgia,serif" font-size="9" fill="#000">C + ½O₂ → CO</text>

  <!-- Right leg: Intermediate → Products -->
  <line x1="610" y1="418" x2="800" y2="222" stroke="#000" stroke-width="2.5" stroke-dasharray="8,4" marker-end="url(#hess_arrow)"/>
  <text x="730" y="345" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">ΔH₃</text>
  <text x="700" y="360" font-family="Georgia,serif" font-size="9" fill="#000">CO + ½O₂ → CO₂</text>

  <!-- Hess's Law equation box -->
  <rect x="350" y="295" width="300" height="55" rx="6" fill="none" stroke="#000" stroke-width="2.5" stroke-dasharray="6,3"/>
  <text x="500" y="320" font-family="Georgia,serif" font-size="14" font-weight="bold" fill="#000" text-anchor="middle">Hess's Law:</text>
  <text x="500" y="340" font-family="Georgia,serif" font-size="13" fill="#000" text-anchor="middle">ΔH₁ = ΔH₂ + ΔH₃</text>

  <!-- Route legend -->
  <line x1="80" y1="530" x2="140" y2="530" stroke="#000" stroke-width="3"/>
  <text x="150" y="534" font-family="Georgia,serif" font-size="11" fill="#000">Direct route (Route 1)</text>
  <line x1="320" y1="530" x2="380" y2="530" stroke="#000" stroke-width="2.5" stroke-dasharray="8,4"/>
  <text x="390" y="534" font-family="Georgia,serif" font-size="11" fill="#000">Indirect route (Route 2: ΔH₂ + ΔH₃)</text>
</svg>`;

