  static compositionPieChartSvg = `<?xml version="1.0" encoding="utf-8"?>
<svg version="1.1" xmlns="http://www.w3.org/2000/svg"
     width="700px" height="700px" viewBox="0 0 700 700">

  <text x="350" y="34" font-family="Georgia,serif" font-size="17" font-weight="bold"
        fill="#000" text-anchor="middle">Percentage Composition — H₂O</text>
  <text x="350" y="56" font-family="Georgia,serif" font-size="12" fill="#000"
        text-anchor="middle">Molar mass: H₂O = 2(1.0) + 16.0 = 18.0 g mol⁻¹</text>

  <!-- Pie chart centre (350,330) radius 200 -->
  <!-- H: 2/18 = 11.1% → 40° arc   O: 16/18 = 88.9% → 320° arc -->

  <!-- O sector: 320° (from 0° to 320°), large arc -->
  <!-- Start at top (270° = -90°), go clockwise -->
  <!-- O: from angle -90° to 230° (320° span) -->
  <!-- In SVG coords: start (350, 130), end at angle 230°-90°=140° from +x → (350+200cos(140°), 330+200sin(140°)) = (350-153.2, 330+128.6) = (196.8, 458.6) -->
  <path d="M350,330 L350,130 A200,200 0 1,1 196,459 Z"
        fill="#fff" stroke="#000" stroke-width="3"/>

  <!-- H sector: 40° arc (from 230° to 270° relative = from end of O to top) -->
  <!-- Start (196,459), end (350,130) -->
  <path d="M350,330 L196,459 A200,200 0 0,1 350,130 Z"
        fill="#000" fill-opacity="0.35" stroke="#000" stroke-width="3"/>

  <!-- Slice labels inside -->
  <!-- O label: centre of large sector at ~80° from top = 350°... place at ~(350+150*cos(10°), 330+150*sin(10°)) ≈ (498, 356) -->
  <text x="460" y="290" font-family="Georgia,serif" font-size="18" font-weight="bold"
        fill="#000" text-anchor="middle">O</text>
  <text x="460" y="312" font-family="Georgia,serif" font-size="15" fill="#000"
        text-anchor="middle">88.9%</text>

  <!-- H label: centre of small sector ~250° from top → (350+150*cos(250°-90°), 330+150*sin(250°-90°)) -->
  <!-- 250°-90°=160° from +x axis → (350+150*cos160°, 330+150*sin160°) = (350-141, 330+51) = (209, 381) -->
  <text x="210" y="400" font-family="Georgia,serif" font-size="16" font-weight="bold"
        fill="#000" text-anchor="middle">H</text>
  <text x="210" y="420" font-family="Georgia,serif" font-size="13" fill="#000"
        text-anchor="middle">11.1%</text>

  <!-- Legend -->
  <rect x="90" y="560" width="520" height="100" rx="6"
        fill="none" stroke="#000" stroke-width="2.5" stroke-dasharray="5,3"/>
  <text x="350" y="582" font-family="Georgia,serif" font-size="13" font-weight="bold"
        fill="#000" text-anchor="middle">Composition Breakdown</text>

  <!-- H legend -->
  <rect x="110" y="594" width="22" height="22" fill="#000" fill-opacity="0.35"
        stroke="#000" stroke-width="2"/>
  <text x="140" y="610" font-family="Georgia,serif" font-size="12" fill="#000">H:  2 × 1.0 = 2.0 g mol⁻¹  →  2.0/18.0 × 100 = 11.1%</text>

  <!-- O legend -->
  <rect x="110" y="624" width="22" height="22" fill="#fff"
        stroke="#000" stroke-width="2"/>
  <text x="140" y="640" font-family="Georgia,serif" font-size="12" fill="#000">O:  1 × 16.0 = 16.0 g mol⁻¹  →  16.0/18.0 × 100 = 88.9%</text>

  <text x="350" y="652" font-family="Georgia,serif" font-size="11" fill="#000"
        text-anchor="middle">Total molar mass = 18.0 g mol⁻¹</text>
</svg>`;

