// molarity → static molaritySvg
static molaritySvg = `<?xml version="1.0" encoding="utf-8"?>
<svg version="1.1" xmlns="http://www.w3.org/2000/svg" width="900px" height="600px" viewBox="0 0 900 600">
  <rect width="900" height="600" fill="#ffffff"/>
  <text x="450" y="28" font-family="Georgia,serif" font-size="16" font-weight="bold" fill="#000" text-anchor="middle">Molarity — Concentration Triangle</text>
  <text x="450" y="46" font-family="Georgia,serif" font-size="11" fill="#333" text-anchor="middle">Relating moles (n), concentration (c) and volume (V)</text>

  <!-- Main triangle -->
  <polygon points="450,100 180,500 720,500" fill="none" stroke="#000" stroke-width="3.5"/>
  <!-- Internal dividers -->
  <line x1="450" y1="100" x2="450" y2="500" stroke="#000" stroke-width="2.5"/>
  <line x1="315" y1="300" x2="585" y2="300" stroke="#000" stroke-width="2.5"/>

  <!-- Three sections labelled -->
  <!-- Top: n (moles) -->
  <text x="450" y="195" font-family="Georgia,serif" font-size="36" font-weight="bold" fill="#000" text-anchor="middle">n</text>
  <text x="450" y="228" font-family="Georgia,serif" font-size="14" fill="#333" text-anchor="middle">moles</text>
  <text x="450" y="248" font-family="Georgia,serif" font-size="12" fill="#333" text-anchor="middle">(mol)</text>

  <!-- Bottom-left: c (concentration) -->
  <text x="300" y="390" font-family="Georgia,serif" font-size="36" font-weight="bold" fill="#000" text-anchor="middle">c</text>
  <text x="300" y="420" font-family="Georgia,serif" font-size="14" fill="#333" text-anchor="middle">concentration</text>
  <text x="300" y="440" font-family="Georgia,serif" font-size="12" fill="#333" text-anchor="middle">(mol dm⁻³)</text>

  <!-- Bottom-right: V (volume) -->
  <text x="600" y="390" font-family="Georgia,serif" font-size="36" font-weight="bold" fill="#000" text-anchor="middle">V</text>
  <text x="600" y="420" font-family="Georgia,serif" font-size="14" fill="#333" text-anchor="middle">volume</text>
  <text x="600" y="440" font-family="Georgia,serif" font-size="12" fill="#333" text-anchor="middle">(dm³)</text>

  <!-- Operation labels -->
  <text x="355" y="200" font-family="Georgia,serif" font-size="13" fill="#000" text-anchor="middle">÷ V</text>
  <text x="545" y="200" font-family="Georgia,serif" font-size="13" fill="#000" text-anchor="middle">÷ c</text>
  <text x="285" y="296" font-family="Georgia,serif" font-size="13" fill="#000" text-anchor="middle">× V</text>
  <text x="615" y="296" font-family="Georgia,serif" font-size="13" fill="#000" text-anchor="middle">× c</text>

  <!-- Formulae box -->
  <rect x="30" y="526" width="840" height="60" rx="5" fill="none" stroke="#000" stroke-width="2" stroke-dasharray="5,3"/>
  <text x="450" y="548" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000" text-anchor="middle">Key Formulae:  c = n / V     |     n = c × V     |     V = n / c</text>
  <text x="450" y="568" font-family="Georgia,serif" font-size="11" fill="#333" text-anchor="middle">Units: c in mol dm⁻³ (M), V in dm³ (L), n in mol. Convert mL → dm³: divide by 1000</text>

  <!-- Example beaker diagram -->
  <text x="80" y="95" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">Worked example:</text>
  <text x="80" y="113" font-family="Georgia,serif" font-size="11" fill="#000">0.5 mol NaCl in 250 mL</text>
  <!-- Beaker -->
  <path d="M84,140 L84,200 Q84,210 94,210 L156,210 Q166,210 166,200 L166,140" fill="none" stroke="#000" stroke-width="2.5"/>
  <line x1="78" y1="140" x2="172" y2="140" stroke="#000" stroke-width="2"/>
  <!-- Solution level -->
  <line x1="86" y1="180" x2="164" y2="180" stroke="#555" stroke-width="1.5" stroke-dasharray="4,3"/>
  <!-- Volume label -->
  <text x="172" y="183" font-family="Georgia,serif" font-size="10" fill="#000">250 mL</text>
  <!-- Dots for solute particles -->
  <circle cx="110" cy="195" r="4" fill="#555" stroke="#000" stroke-width="1"/>
  <circle cx="130" cy="190" r="4" fill="#555" stroke="#000" stroke-width="1"/>
  <circle cx="150" cy="197" r="4" fill="#555" stroke="#000" stroke-width="1"/>
  <circle cx="120" cy="200" r="4" fill="#555" stroke="#000" stroke-width="1"/>
  <circle cx="140" cy="202" r="4" fill="#555" stroke="#000" stroke-width="1"/>
  <!-- Calculation -->
  <text x="78" y="230" font-family="Georgia,serif" font-size="11" fill="#000">V = 250 mL = 0.25 dm³</text>
  <text x="78" y="246" font-family="Georgia,serif" font-size="11" fill="#000">c = 0.5 / 0.25</text>
  <text x="78" y="262" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">c = 2.0 mol dm⁻³</text>
</svg>`;

