// ─── REACTION ENERGY PROFILE ───────────────────────────────────────────────────
static energyProfileSvg = `<?xml version="1.0" encoding="utf-8"?>
<svg version="1.1" xmlns="http://www.w3.org/2000/svg"
     width="900px" height="600px" viewBox="0 0 900 600">

  <!-- Title -->
  <text x="450" y="30" font-family="Georgia,serif" font-size="15" font-weight="bold"
        fill="#000" text-anchor="middle">Reaction Energy Profile — Exothermic Reaction</text>
  <text x="450" y="50" font-family="Georgia,serif" font-size="10" fill="#555"
        text-anchor="middle">Potential energy vs reaction coordinate; activation energy and ΔH shown</text>

  <!-- ── AXES ── -->
  <!-- Y-axis -->
  <line x1="80" y1="40" x2="80" y2="500" stroke="#000" stroke-width="2.5"/>
  <polygon points="75,42 80,28 85,42" fill="#000"/>
  <text x="30" y="280" font-family="Georgia,serif" font-size="12" fill="#000"
        transform="rotate(-90,30,280)">Potential Energy / kJ mol⁻¹</text>

  <!-- X-axis -->
  <line x1="80" y1="500" x2="840" y2="500" stroke="#000" stroke-width="2.5"/>
  <polygon points="838,495 852,500 838,505" fill="#000"/>
  <text x="450" y="535" font-family="Georgia,serif" font-size="12" fill="#000"
        text-anchor="middle">Reaction Coordinate →</text>

  <!-- ── ENERGY CURVE (exothermic) ── -->
  <!-- Reactants plateau at y=200, TS peak at y=90, Products plateau at y=340 -->
  <path d="M100,200 Q160,200 220,200 Q290,190 330,90 Q370,30 400,90
           Q440,170 480,340 Q520,360 580,360 Q680,360 800,360"
        fill="none" stroke="#000" stroke-width="3"/>

  <!-- ── REACTANTS LEVEL LINE ── -->
  <line x1="100" y1="200" x2="230" y2="200" stroke="#555" stroke-width="1.5"
        stroke-dasharray="5,3"/>
  <text x="92" y="204" font-family="Georgia,serif" font-size="10" fill="#000"
        text-anchor="end">Reactants</text>

  <!-- ── PRODUCTS LEVEL LINE ── -->
  <line x1="480" y1="360" x2="800" y2="360" stroke="#555" stroke-width="1.5"
        stroke-dasharray="5,3"/>
  <text x="808" y="364" font-family="Georgia,serif" font-size="10" fill="#000">Products</text>

  <!-- ── TRANSITION STATE ── -->
  <line x1="400" y1="90" x2="400" y2="40" stroke="#555" stroke-width="1.5"
        stroke-dasharray="4,3"/>
  <text x="400" y="34" font-family="Georgia,serif" font-size="10" fill="#000"
        text-anchor="middle">‡ Transition State</text>
  <circle cx="400" cy="90" r="5" fill="#000"/>

  <!-- ── ACTIVATION ENERGY ARROW (Ea) ── -->
  <!-- Upward arrow from reactants level to TS -->
  <line x1="300" y1="200" x2="300" y2="92" stroke="#000" stroke-width="2"/>
  <polygon points="295,96 300,82 305,96" fill="#000"/>
  <polygon points="295,196 300,210 305,196" fill="#000"/>
  <text x="310" y="148" font-family="Georgia,serif" font-size="12" font-weight="bold"
        fill="#000">Eₐ</text>
  <text x="310" y="162" font-family="Georgia,serif" font-size="9" fill="#555">(activation energy)</text>

  <!-- ── ΔH ARROW (negative = exothermic) ── -->
  <line x1="640" y1="200" x2="640" y2="358" stroke="#000" stroke-width="2"/>
  <polygon points="635,196 640,182 645,196" fill="#000"/>
  <polygon points="635,354 640,368 645,354" fill="#000"/>
  <text x="652" y="284" font-family="Georgia,serif" font-size="12" font-weight="bold"
        fill="#000">ΔH</text>
  <text x="652" y="298" font-family="Georgia,serif" font-size="10" fill="#000">(−ve)</text>
  <text x="652" y="312" font-family="Georgia,serif" font-size="9" fill="#555">exothermic</text>

  <!-- ── CATALYST CURVE ── -->
  <!-- Lower TS peak at y=155 with catalyst -->
  <path d="M100,200 Q170,200 240,200 Q300,195 340,155 Q370,110 400,155
           Q435,205 470,340 Q505,360 560,360"
        fill="none" stroke="#555" stroke-width="2" stroke-dasharray="6,4"/>
  <text x="340" y="140" font-family="Georgia,serif" font-size="9" fill="#555">‡ with catalyst</text>
  <line x1="350" y1="144" x2="362" y2="152" stroke="#555" stroke-width="1"/>

  <!-- Eₐ (catalysed) label -->
  <text x="176" y="180" font-family="Georgia,serif" font-size="9" fill="#555">Eₐ (cat.)</text>
  <line x1="220" y1="185" x2="220" y2="155" stroke="#555" stroke-width="1.5"
        stroke-dasharray="3,2"/>
  <polygon points="215,158 220,145 225,158" fill="#555"/>

  <!-- ── ANNOTATIONS ── -->
  <text x="155" y="185" font-family="Georgia,serif" font-size="10" fill="#000">A + B</text>
  <text x="700" y="348" font-family="Georgia,serif" font-size="10" fill="#000">C + D</text>

  <!-- ── LEGEND ── -->
  <line x1="90" y1="430" x2="130" y2="430" stroke="#000" stroke-width="3"/>
  <text x="136" y="434" font-family="Georgia,serif" font-size="10" fill="#000">Uncatalysed pathway</text>
  <line x1="320" y1="430" x2="360" y2="430" stroke="#555" stroke-width="2"
        stroke-dasharray="6,4"/>
  <text x="366" y="434" font-family="Georgia,serif" font-size="10" fill="#555">Catalysed pathway (lower Eₐ)</text>

  <!-- ── KEY FACTS BOX ── -->
  <rect x="80" y="448" width="760" height="100" rx="5" fill="none"
        stroke="#000" stroke-width="1.8" stroke-dasharray="5,3"/>
  <text x="460" y="468" font-family="Georgia,serif" font-size="11"
        font-weight="bold" fill="#000" text-anchor="middle">Key Definitions</text>
  <text x="96" y="488" font-family="Georgia,serif" font-size="10" fill="#000">Eₐ (activation energy): minimum energy for reactants to reach transition state</text>
  <text x="96" y="506" font-family="Georgia,serif" font-size="10" fill="#000">ΔH (enthalpy change): H(products) − H(reactants); negative = exothermic; positive = endothermic</text>
  <text x="96" y="524" font-family="Georgia,serif" font-size="10" fill="#555">Catalyst: lowers Eₐ (provides alternative pathway); ΔH unchanged; not consumed in reaction</text>
  <text x="96" y="542" font-family="Georgia,serif" font-size="10" fill="#555">Transition state (‡): highest-energy point; cannot be isolated</text>

</svg>`;

